import prometheus_client
from prometheus_client import Summary, Counter

# Define a custom metrics registry
metrics = prometheus_client.CollectorRegistry()

# Create a metric to track HTTP requests with labels for user_id, session_id, and full request path
http_requests = Summary('http_requests', 'HTTP Requests', ['user_id', 'session_id', 'full_request_path'])
metrics.register(http_requests)

# Create a metric to count the number of unique user-path combinations
unique_users = Counter('unique_users', 'Unique Users', ['user_id', 'session_id', 'full_request_path'])
metrics.register(unique_users)